// src/components/CartItem/index.jsx

import React from 'react';
import { useDispatch } from 'react-redux';
import { 
    incrementItem,   // ✅ ИСПОЛЬЗУЕМ ПРАВИЛЬНОЕ ИМЯ
    decrementItem,   // ✅ ИСПОЛЬЗУЕМ ПРАВИЛЬНОЕ ИМЯ
    removeFromCart 
} from '../../store/slices/cartSlice';
import { getImageUrl } from '../../utils/fixUrl'; // Предполагаемая утилита
import s from './CartItem.module.css';

const CartItem = ({ item }) => {
  const dispatch = useDispatch();
  const imageUrl = getImageUrl(item.image);

  // Используем quantity, если count не определен
  const count = item.quantity || 1; 

  // 🔑 КЛЮЧЕВОЕ ИСПРАВЛЕНИЕ: Передаем только ID
  const handleIncrease = () => dispatch(incrementItem(item.id));
  const handleDecrease = () => dispatch(decrementItem(item.id));
  const handleRemove = () => dispatch(removeFromCart(item.id));

  // Расчет цен
  const price = item.price || 0;
  const discontPrice = item.discont_price || 0;
  const finalPrice = discontPrice > 0 ? discontPrice : price;

  const unitPrice = finalPrice.toFixed(2);
  const itemTotalPrice = (finalPrice * count).toFixed(2);

  const originalPrice = (discontPrice > 0 && price > discontPrice) 
    ? price.toFixed(2) 
    : null;

  return (
    <div className={s.item}>
      <div className={s.imageWrapper}>
        <img src={imageUrl} alt={item.title} className={s.image} />
      </div>

      <div className={s.details}>
        <div className={s.titleRow}>
          <h3 className={s.title}>{item.title}</h3>
          {/* Кнопка удаления X */}
          <button className={s.removeButton} onClick={handleRemove}>
             &times;
          </button>
        </div>

        <div className={s.bottomRow}>
          {/* Контроль количества */}
          <div className={s.quantity}>
            <button 
                onClick={handleDecrease} 
                disabled={count <= 1} // Отключаем, если 1
            >
                —
            </button>
            <span className={s.count}>{count}</span>
            <button onClick={handleIncrease}>
                +
            </button>
          </div>

          {/* Общая цена за позицию */}
          <p className={s.totalPrice}>{itemTotalPrice} $</p>

          {/* Цена до скидки (зачеркнутая) */}
          {originalPrice && <p className={s.originalPrice}>{originalPrice}</p>}
        </div>
      </div>
    </div>
  );
};

export default CartItem;
